1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 0.1;
3	
4	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	interface Item {
13	  type: string;
14	}
15	
16	interface QuoteStep {
17	  op: "quote";
18	  items: Item[];
19	}
20	
21	interface Scenario {
22	  customer: { yearsWithMHPCO: number };
23	  steps: QuoteStep[];
24	}
25	
26	const itemPremium = (item: Item): number => {
27	  const base = BASE_PREMIUM_BY_TYPE[item.type];
28	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_SURCHARGE;
29	  return base + firstInsuranceSurcharge;
30	};
31	
32	const sumItemPremiums = (items: Item[]): number =>
33	  items.reduce((sum, item) => sum + itemPremium(item), 0);
34	
35	const quoteStep = ({ items }: QuoteStep) => ({
36	  premium: Math.ceil(sumItemPremiums(items) + PROCESSING_FEE),
37	});
38	
39	export const processScenario = ({ steps }: Scenario): unknown => ({
40	  results: steps.map(quoteStep),
41	});
42

